={{ (() => {
  // Get all analytics items (may be array or single item)
  const items = $items('📊 Read Analytics History') || [];
  const rows = items.map(i => i.json).filter(r => r['Total Views']);

  // Sort by Total Views descending, take top 3
  rows.sort((a, b) => (parseInt(b['Total Views']) || 0) - (parseInt(a['Total Views']) || 0));
  const top3 = rows.slice(0, 3);
  const bottom3 = rows.sort((a, b) => (parseInt(a['Total Views']) || 0) - (parseInt(b['Total Views']) || 0)).slice(0, 3);

  let context = '';
  if (top3.length > 0) {
    context += 'TOP PERFORMERS (replicate these patterns):\n';
    top3.forEach((r, i) => {
      context += (i+1) + '. ' + r['File Code Name'] + ' — ' + parseInt(r['Total Views']).toLocaleString() + ' views, ' + r['Engagement Rate'] + ' engagement, Top platform: ' + r['Top Platform'] + ', Tier: ' + r['Tier'] + '\n';
    });
  }
  if (bottom3.length > 0) {
    context += '\nWEAK PERFORMERS (avoid these patterns):\n';
    bottom3.forEach((r, i) => {
      context += (i+1) + '. ' + r['File Code Name'] + ' — ' + parseInt(r['Total Views']).toLocaleString() + ' views, Tier: ' + r['Tier'] + '\n';
    });
  }
  if (!context) context = 'No analytics data yet — this is an early content run.';

  return JSON.stringify({ performance_context: context, total_videos_analyzed: rows.length });
})() }}

